use crate::polyglot_traits::{AstParser, PolyglotFunction, PolyglotStatement, PolyglotExpression};

pub struct LeanParser;

impl AstParser for LeanParser {
    fn parse(&self, source_text: &str, target_export_name: &str) -> Result<PolyglotFunction, String> {
        let mut in_target = false;
        let mut in_by_block = false;
        let mut extracted_params = Vec::new();
        let mut extracted_statements = Vec::new();

        for line in source_text.lines() {
            let t_line = line.trim();

            if in_by_block {
                if t_line.starts_with("end ") || t_line.starts_with("theorem ") || t_line.starts_with("def ") || t_line.starts_with("-- ═") {
                    break;
                }
                if t_line.is_empty() || t_line.starts_with("--") || t_line.starts_with("/-") || t_line.starts_with("-/") {
                    continue;
                }

                // Split tactics by `<;>`
                let parts: Vec<&str> = t_line.split("<;>").collect();
                for part in parts {
                    let sub_t = part.trim();
                    if sub_t.is_empty() {
                        continue;
                    }
                    
                    if sub_t.starts_with("have ") {
                        if let Some(pos) = sub_t.find(":=") {
                            let binding_part = sub_t[5..pos].trim();
                            let binding_name = binding_part.split(':').next().unwrap().trim().to_string();
                            let init_part = sub_t[pos+2..].trim();
                            
                            let mut args = Vec::new();
                            let mut callee = init_part.to_string();

                            let init_tokens: Vec<&str> = init_part.split_whitespace().collect();
                            if init_tokens.len() > 1 {
                                callee = init_tokens[0].to_string();
                                for t in &init_tokens[1..] {
                                    args.push(PolyglotExpression::Identifier(t.to_string()));
                                }
                            }

                            if args.is_empty() {
                                extracted_statements.push(PolyglotStatement::VariableDeclaration {
                                    bindings: vec![binding_name],
                                    init: Some(PolyglotExpression::Identifier(callee)),
                                });
                            } else {
                                extracted_statements.push(PolyglotStatement::VariableDeclaration {
                                    bindings: vec![binding_name],
                                    init: Some(PolyglotExpression::Call {
                                        callee: Box::new(PolyglotExpression::Identifier(callee)),
                                        args,
                                    }),
                                });
                            }
                        } else {
                            extracted_statements.push(PolyglotStatement::Expression(PolyglotExpression::Identifier(sub_t.to_string())));
                        }
                    } else if sub_t.starts_with("exact ") || sub_t.starts_with("apply ") {
                        let tokens: Vec<&str> = sub_t.split_whitespace().collect();
                        let callee = tokens[0].to_string();
                        let mut args = Vec::new();
                        for t in &tokens[1..] {
                            args.push(PolyglotExpression::Identifier(t.to_string()));
                        }
                        if callee == "exact" {
                           if args.len() == 1 {
                               extracted_statements.push(PolyglotStatement::Return(Some(PolyglotExpression::Identifier(tokens[1].to_string()))));
                           } else {
                               extracted_statements.push(PolyglotStatement::Return(Some(PolyglotExpression::Call {
                                   callee: Box::new(PolyglotExpression::Identifier(callee)),
                                   args,
                               })));
                           }
                        } else {
                           extracted_statements.push(PolyglotStatement::Expression(PolyglotExpression::Call {
                               callee: Box::new(PolyglotExpression::Identifier(callee)),
                               args,
                           }));
                        }
                    } else {
                        let tokens: Vec<&str> = sub_t.split_whitespace().collect();
                        if tokens.len() == 1 {
                            extracted_statements.push(PolyglotStatement::Expression(PolyglotExpression::Identifier(tokens[0].to_string())));
                        } else {
                            let callee = tokens[0].to_string();
                            let mut args = Vec::new();
                            for t in &tokens[1..] {
                                args.push(PolyglotExpression::Identifier(t.to_string()));
                            }
                            extracted_statements.push(PolyglotStatement::Expression(PolyglotExpression::Call {
                                callee: Box::new(PolyglotExpression::Identifier(callee)),
                                args,
                            }));
                        }
                    }
                }
            } else {
                if (t_line.starts_with("theorem ") || t_line.starts_with("def ") || t_line.starts_with("lemma ")) && t_line.contains(target_export_name) {
                    in_target = true;
                    // Extract basic parameter bindings like `(R1 R2 forkWidth1 : Nat)`
                    let param_matches: Vec<_> = t_line.match_indices('(').collect();
                    for (start_idx, _) in param_matches {
                        if let Some(end_idx) = t_line[start_idx..].find(')') {
                            let inside = &t_line[start_idx+1..start_idx+end_idx];
                            let parts: Vec<&str> = inside.split(':').collect();
                            if parts.len() == 2 {
                                let names: Vec<&str> = parts[0].split_whitespace().collect();
                                for n in names {
                                    // Skip typeclasses like [Something]
                                    if !n.starts_with('[') {
                                        extracted_params.push(n.to_string());
                                    }
                                }
                            }
                        }
                    }

                    if t_line.contains(":= by") || line.contains(":= by") {
                        in_by_block = true;
                    }
                } else if in_target && (t_line.contains(":= by") || t_line.ends_with("by")) {
                    in_by_block = true;
                }
            }
        }

        if !in_target {
            return Err(format!("Could not locate target {} in lean source text.", target_export_name));
        }

        Ok(PolyglotFunction {
            name: target_export_name.to_string(),
            params: extracted_params,
            body: extracted_statements,
        })
    }
}
